// ---- FHA calculator ----
  const $=id=>document.getElementById(id);
  const fmt=n=>'$'+Math.round(n).toLocaleString('en-US');
  function calc(){
    const price=+$('price').value;
    const downPct=+$('down').value;
    const rate=+$('rate').value;
    const term=+$('term').value;
    const down=price*downPct/100;
    let base=price-down;
    const upfrontMIP=base*0.0175;       // 1.75% upfront, financed
    const loan=base+upfrontMIP;
    const r=rate/100/12, n=term*12;
    const pi = r>0 ? loan*r*Math.pow(1+r,n)/(Math.pow(1+r,n)-1) : loan/n;
    const mip=loan*0.0055/12;           // 0.55% annual
    const tax=price*0.01/12;            // ~1% annual
    const ins=price*0.006/12;           // ~0.6% annual
    const total=pi+mip+tax+ins;
    $('vPrice').textContent=fmt(price);
    $('vDown').textContent=downPct+'% · '+fmt(down);
    $('vRate').textContent=rate.toFixed(3).replace(/0+$/,'').replace(/\.$/,'')+'%';
    $('vTerm').textContent=term+' years';
    $('payTotal').innerHTML=fmt(total)+'<small>/mo</small>';
    $('bPI').textContent=fmt(pi);
    $('bMIP').textContent=fmt(mip);
    $('bTax').textContent=fmt(tax);
    $('bIns').textContent=fmt(ins);
    $('bLoan').textContent=fmt(loan);
  }
  ['price','down','rate','term'].forEach(id=>$(id).addEventListener('input',calc));
  calc();
